sys_ui_action.script:
// Copyrights belong to Discover Technologies LLC. © 2019 Discover Technologies LLC
// Script Continued Below
export_task();
function export_task() {

	current.insert();

	//HT - STRY0058721
	if(current.u_export_task_information == true){

		var instance = gs.getProperty("glide.servlet.uri");
		var recordSys_Id = current.parent;
		var fileName = current.parent.task_name;
		var taskTable = 'x_153465_discovert_route_task_instance';

		try {
			// EXP - STRY0069767
			var r = new sn_ws.RESTMessageV2('x_153465_discovert.Email Task Information', 'Email Task Information POST');
			r.setStringParameterNoEscape('record_sys_id', recordSys_Id);
			r.setStringParameterNoEscape('instance', instance);
			r.setStringParameterNoEscape('taskTable', 'x_153465_discovert_route_task_instance');
			// EXP - STRY0069767
			r.saveResponseBodyAsAttachment('x_153465_discovert_tasker_email', current.getValue("sys_id"), fileName+".pdf");
			var response = r.execute();

		}
		catch(ex) {
			var message = ex.message;
		}

		//TODO: HT once tree level is finished if check attachemnts check call glidesystem and pass table = task tree and pass current.parent.U_top_task.U_task_tree.sys_id
	}


	//if the export my attachments checkbox is checked attach all my attachments
	if(current.u_export_my_attachments == true){
		// EXP - STRY0069767
		GlideSysAttachment.copy('x_153465_discovert_route_task_instance', current.parent, 'x_153465_discovert_tasker_email', current.getValue("sys_id"));
	}

	//if the export all shared attachments checkbox is checked attach all shared attachments
	if(current.u_export_all_shared_attachments == true){
		// EXP - STRY0069767
		GlideSysAttachment.copy('x_153465_discovert_task_tree',  current.parent.u_top_task.u_task_tree, 'x_153465_discovert_tasker_email', current.getValue("sys_id"));
	}

	//if the export my documents checkbox is checked , attach my documents
	if(current.u_export_my_documents == true){

		var DocIntViewSysID = gs.getProperty('x_153465_discovert.DocIntViewSysIDTasks');
		var cmd = new x_dtll2_contentint.CopyAndMoveDocuments();
		// EXP - STRY0069767
		var eventArgs = {
			"sourceTable" : "x_153465_discovert_route_task_instance",
			"sourceTableItemID" : current.getValue('parent'),
			"isAsync" :false,
			"event" : "x_dtll2_contentint.SPtoSN",
			"sourceView": DocIntViewSysID,
			"targetTableName" : "x_153465_discovert_tasker_email",
			"targetTableItemID" :  current.getValue("sys_id")
		};

		cmd.createEvent(eventArgs);
	}

	//if the export all shared documents checkbox is checked, attach all shared documents
	if(current.u_export_all_shared_documents == true){

		var DocIntSharedViewSysID = gs.getProperty('x_153465_discovert.DocIntSharedDocumentsViewSysIDTasks');
		var cmd2 = new x_dtll2_contentint.CopyAndMoveDocuments();
		// EXP - STRY0069767
		var eventArgs2 = {
			"sourceTable" : "x_153465_discovert_route_task_instance",
			"sourceTableItemID" : current.getValue('parent'),
			"isAsync" : false,
			"event" : "x_dtll2_contentint.SPtoSN",
			"sourceView": DocIntSharedViewSysID,
			"targetTableName" : "x_153465_discovert_tasker_email",
			"targetTableItemID" :  current.getValue("sys_id")
		};

		cmd2.createEvent(eventArgs2);
	}
	//HT - STRY0058721
	//collect the list of recipients
	var recipientList = current.u_recipient.toString();
	var CurrentUserEmail = gs.getUser().getEmail();
	var recipients = [recipientList, CurrentUserEmail];

	gs.eventQueue("x_153465_discovert.EmailTaskInformation", current, '', recipients.toString());

	//HT -STRY0053835
	//update worknotes on the tasker record
	var parentTaskNumber = current.parent.taskernumber;
	var subject = current.u_subject;
	var recipient = current.getDisplayValue('u_recipient');

	var grTask = new GlideRecord('x_153465_discovert_route_task_instance');
	grTask.addQuery('taskernumber', parentTaskNumber);
	grTask.query();

	if(grTask.next()){
		grTask.work_notes = "Requested an export of " + parentTaskNumber +", " + subject  + " that was sent to " + recipient.toString();
		grTask.update();
	}
	//HT -STRY0053835

}
